### Emit Framework (`emit.h` - lines 1-150)

Output generation uses a simple character buffer approach:

```c
#define EMIT_BUF_SIZE 4096
char emit_buf[EMIT_BUF_SIZE];
int emit_pos;

/* Core functions */
void emit_char(int ch);      /* append single char */
void emit_str(char *s);      /* append string */
void emit_line(char *s);     /* append string + newline */
void emit_int(int n);        /* append decimal integer */
void emit_instr(char *s);    /* emit indented instruction + newline */
void emit_comment(char *s);  /* emit indented comment + newline */

/* Label functions */
int emit_new_label(void);      /* allocate unique label number */
void emit_label(int n);        /* emit "Ln:" with newline */
void emit_label_ref(int n);    /* emit "Ln" without colon or newline */
void emit_named_label(char *name);  /* emit "_name:" */
void emit_named_ref(char *name);    /* emit "_name" */

#define EMIT_INDENT "        "  /* 8-space indentation */
```

