1	/* emit.h -- Assembly emitter framework for PL/SW compiler */
2	/* Manages output buffer, sections, labels, and instruction emission */
3	
4	#ifndef EMIT_H
5	#define EMIT_H
6	
7	#include "str.h"
8	
9	/* --- Output buffer --- */
10	
11	/* 4KB output buffer for generated assembly */
12	#define EMIT_BUF_SIZE 4096
13	
14	char emit_buf[EMIT_BUF_SIZE];
15	int emit_pos;     /* current write position */
16	int emit_err;     /* error flag */
17	
18	/* --- Label counter --- */
19	
20	int emit_label_next;  /* next unique label number */
21	
22	/* --- Section tracking --- */
23	
24	int emit_in_data;  /* 1 if currently in .data section, 0 for .text */
25	
26	/* --- Indentation --- */
27	
28	#define EMIT_INDENT "        "  /* 8 spaces, matching tc24r output */
29	
30	/* --- Core emit functions --- */
31	
32	void emit_init(void) {
33	    emit_pos = 0;
34	    emit_err = 0;
35	    emit_label_next = 0;
36	    emit_in_data = 0;
37	    mem_set(emit_buf, 0, 256);  /* clear start of buffer */
38	}
39	
40	/* Append a single character to the output buffer */
41	void emit_char(int ch) {
42	    if (emit_pos >= EMIT_BUF_SIZE - 1) {
43	        emit_err = 1;
44	        return;
45	    }
46	    emit_buf[emit_pos] = ch;
47	    emit_pos = emit_pos + 1;
48	}
49	
50	/* Append a string to the output buffer */
51	void emit_str(char *s) {
52	    while (*s) {
53	        emit_char(*s);
54	        s = s + 1;
55	    }
56	}
57	
58	/* Append a newline */
59	void emit_nl(void) {
60	    emit_char(10);
61	}
62	
63	/* Append a string followed by newline */
64	void emit_line(char *s) {
65	    emit_str(s);
66	    emit_nl();
67	}
68	
69	/* Emit an integer as decimal string */
70	void emit_int(int n) {
71	    char buf[12];
72	    int i;
73	    int neg;
74	    int d;
75	
76	    if (n == 0) {
77	        emit_char(48);
78	        return;
79	    }
80	
81	    neg = 0;
82	    if (n < 0) {
83	        neg = 1;
84	        n = 0 - n;
85	    }
86	
87	    i = 0;
88	    while (n > 0) {
89	        d = n;
90	        /* manual modulo: d = n % 10 */
91	        while (d >= 10) {
92	            d = d - 10;
93	        }
94	        buf[i] = 48 + d;
95	        i = i + 1;
96	        n = n / 10;
97	    }
98	
99	    if (neg) {
100	        emit_char(45);  /* '-' */
101	    }
102	
103	    /* emit digits in reverse */
104	    while (i > 0) {
105	        i = i - 1;
106	        emit_char(buf[i]);
107	    }
108	}
109	
110	/* --- Label generation --- */
111	
112	/* Generate a unique label name into buf. Returns label number. */
113	int emit_new_label(void) {
114	    int n = emit_label_next;
115	    emit_label_next = emit_label_next + 1;
116	    return n;
117	}
118	
119	/* Emit a label definition (e.g., "L42:") */
120	void emit_label(int label_num) {
121	    emit_char(76);  /* 'L' */
122	    emit_int(label_num);
123	    emit_char(58);  /* ':' */
124	    emit_nl();
125	}
126	
127	/* Emit a label reference (e.g., "L42") without colon or newline */
128	void emit_label_ref(int label_num) {
129	    emit_char(76);  /* 'L' */
130	    emit_int(label_num);
131	}
132	
133	/* Emit a named label (e.g., "_main:") */
134	void emit_named_label(char *name) {
135	    emit_char(95);  /* '_' */
136	    emit_str(name);
137	    emit_char(58);  /* ':' */
138	    emit_nl();
139	}
140	
141	/* Emit a named label reference without colon */
142	void emit_named_ref(char *name) {
143	    emit_char(95);  /* '_' */
144	    emit_str(name);
145	}
146	
147	/* --- Section management --- */
148	
149	void emit_text_section(void) {
150	    if (emit_in_data) {
151	        emit_nl();
152	        emit_str(EMIT_INDENT);
153	        emit_line(".text");
154	        emit_in_data = 0;
155	    }
156	}
157	
158	void emit_data_section(void) {
159	    if (!emit_in_data) {
160	        emit_nl();
161	        emit_str(EMIT_INDENT);
162	        emit_line(".data");
163	        emit_in_data = 1;
164	    }
165	}
166	
167	/* --- Instruction emission --- */
168	
169	/* Emit a .globl directive for a symbol */
170	void emit_global(char *name) {
171	    emit_str(EMIT_INDENT);
172	    emit_str(".globl  ");
173	    emit_named_ref(name);
174	    emit_nl();
175	}
176	
177	/* Emit an instruction with no operands (e.g., "nop") */
178	void emit_instr0(char *op) {
179	    emit_str(EMIT_INDENT);
180	    emit_str(op);
181	    emit_nl();
182	}
183	
184	/* Emit an instruction with one operand (e.g., "push fp") */
185	void emit_instr1(char *op, char *arg1) {
186	    emit_str(EMIT_INDENT);
187	    emit_str(op);
188	    emit_str("     ");
189	    emit_str(arg1);
190	    emit_nl();
191	}
192	
193	/* Emit an instruction with two operands (e.g., "mov fp,sp") */
194	void emit_instr2(char *op, char *arg1, char *arg2) {
195	    emit_str(EMIT_INDENT);
196	    emit_str(op);
197	    emit_str("     ");
198	    emit_str(arg1);
199	    emit_char(44);  /* ',' */
200	    emit_str(arg2);
201	    emit_nl();
202	}
203	
204	/* Emit a raw instruction line (already formatted) */
205	void emit_instr(char *line) {
206	    emit_str(EMIT_INDENT);
207	    emit_line(line);
208	}
209	
210	/* --- Comment emission --- */
211	
212	/* Emit a comment line (e.g., "; PL/SW: x = y + 1;") */
213	void emit_comment(char *text) {
214	    emit_str(EMIT_INDENT);
215	    emit_str("; ");
216	    emit_line(text);
217	}
218	
219	/* Emit a source-line tracking comment */
220	void emit_source_line(char *source) {
221	    emit_comment(source);
222	}
223	
224	/* --- Data emission helpers --- */
225	
226	/* Emit a .byte directive */
227	void emit_byte(int val) {
228	    emit_str(EMIT_INDENT);
229	    emit_str(".byte   ");
230	    emit_int(val);
231	    emit_nl();
232	}
233	
234	/* Emit a .word directive (24-bit on COR24) */
235	void emit_word(int val) {
236	    emit_str(EMIT_INDENT);
237	    emit_str(".word   ");
238	    emit_int(val);
239	    emit_nl();
240	}
241	
242	/* Emit an ASCII string in .data section */
243	void emit_ascii(char *s) {
244	    emit_str(EMIT_INDENT);
245	    emit_str(".ascii  \"");
