    ast_init();
    sym_init();
    types_init();
    layout_init();
    emit_init();
    cg_init();
    cg_static_init();

    parse_init("PROC PRINT_INT(V INT(24)); END; PROC TEST3(); DCL ARR(5) INT(24); DCL I INT(24); DO I = 0 TO 4; ARR(I) = I + 1; END; CALL PRINT_INT(ARR(2)); END;");
    prog = parse_program();
    if (parse_err) {
