    cg_assign(asgn);
    uart_putstr(emit_output());
    if (cg_err) { uart_puts("  FAIL: cg_err set"); errs = errs + 1; }

    /* Test 5: Assign then load back (assign X=99, then generate load of X) */
    uart_puts("--- asgn: assign+load ---");
    arena_init();
    ast_init();
    sym_init();
    emit_init();
    cg_init();
    si = sym_insert("V", TYPE_INT24, 3, STOR_AUTO);
    sym_offset[si] = -9;
